import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import {
  CallToolRequestSchema,
  ListToolsRequestSchema,
} from "@modelcontextprotocol/sdk/types.js";
import * as fs from "fs";
import * as path from "path";
import * as os from "os";

const PARTNER_IP = process.env.PARTNER_IP || "127.0.0.1";
const PARTNER_PORT = parseInt(process.env.PARTNER_PORT || "8788");
const LOCAL_PORT = parseInt(process.env.LOCAL_PORT || "8788");
const AGENT_NAME = process.env.AGENT_NAME || "Partner";

// ── Persistent log ──────────────────────────────────────────────────

const LOG_DIR = path.join(os.homedir(), ".agent-bridge");
const LOG_FILE = path.join(LOG_DIR, "messages.json");

if (!fs.existsSync(LOG_DIR)) fs.mkdirSync(LOG_DIR, { recursive: true });
if (!fs.existsSync(LOG_FILE)) fs.writeFileSync(LOG_FILE, "[]");

function appendToLog(msg: Message) {
  try {
    const existing = JSON.parse(fs.readFileSync(LOG_FILE, "utf-8")) as Message[];
    existing.push(msg);
    fs.writeFileSync(LOG_FILE, JSON.stringify(existing, null, 2));
  } catch {
    // non-fatal — in-memory inbox still works
  }
}

// ── Message inbox ───────────────────────────────────────────────────

interface Message {
  from: string;
  message: string;
  timestamp: string;
}

const inbox: Message[] = [];

