import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { CallToolRequestSchema, ListToolsRequestSchema } from "@modelcontextprotocol/sdk/types.js";
import * as fs from "fs";
import * as path from "path";
import * as os from "os";

const PARTNER_IP = process.env.PARTNER_IP || "127.0.0.1";
const PARTNER_PORT = parseInt(process.env.PARTNER_PORT || "8788");
const LOCAL_PORT = parseInt(process.env.LOCAL_PORT || "8788");
const AGENT_NAME = process.env.AGENT_NAME || "Partner";

interface Message { from: string; message: string; timestamp: string; thread_id?: string; }
interface SharedFile { from: string; filename: string; content: string; timestamp: string; }
interface Task { id: string; from: string; title: string; description: string; status: "pending" | "in_progress" | "done"; timestamp: string; }

const LOG_DIR = path.join(os.homedir(), ".agent-bridge");
const LOG_FILE = path.join(LOG_DIR, "messages.json");
if (!fs.existsSync(LOG_DIR)) fs.mkdirSync(LOG_DIR, { recursive: true });
if (!fs.existsSync(LOG_FILE)) fs.writeFileSync(LOG_FILE, "[]");

function appendToLog(msg: Message) {
  try {
    const existing = JSON.parse(fs.readFileSync(LOG_FILE, "utf-8")) as Message[];
    existing.push(msg);
    fs.writeFileSync(LOG_FILE, JSON.stringify(existing, null, 2));
  } catch { }
}

const inbox: Message[] = [];
const sharedFiles: SharedFile[] = [];
const assignedTasks: Task[] = [];

function makeId(): string { return Math.random().toString(36).slice(2, 9); }

async function postToPartner(payload: object): Promise<{ ok: boolean; error?: string }> {
  try {
    const response = await fetch(`http://${PARTNER_IP}:${PARTNER_PORT}`, {
      method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify(payload),
    });
    return response.ok ? { ok: true } : { ok: false, error: `HTTP ${response.status}` };
  } catch (error: unknown) {
    return { ok: false, error: error instanceof Error ? error.message : String(error) };
  }
}

