  tools: [
    { name: "send_message", description: `Send a message to ${AGENT_NAME}'s Claude Code agent. Optionally tag with thread_id.`, inputSchema: { type: "object" as const, properties: { message: { type: "string" }, thread_id: { type: "string" } }, required: ["message"] } },
    { name: "check_messages", description: `Check for new messages from ${AGENT_NAME}'s agent. Clears inbox on read.`, inputSchema: { type: "object" as const, properties: {} } },
    { name: "ping_partner", description: `Check if ${AGENT_NAME}'s agent is online.`, inputSchema: { type: "object" as const, properties: {} } },
    { name: "share_file", description: `Share a local file with ${AGENT_NAME}'s agent. Auto-saved to ~/agent-bridge-files/ on their machine.`, inputSchema: { type: "object" as const, properties: { file_path: { type: "string" }, note: { type: "string" } }, required: ["file_path"] } },
    { name: "assign_task", description: `Assign a task to ${AGENT_NAME}'s agent.`, inputSchema: { type: "object" as const, properties: { title: { type: "string" }, description: { type: "string" } }, required: ["title", "description"] } },
    { name: "check_tasks", description: "See tasks assigned to you by the partner.", inputSchema: { type: "object" as const, properties: {} } },
    { name: "complete_task", description: "Mark an assigned task done and notify partner.", inputSchema: { type: "object" as const, properties: { task_id: { type: "string" }, result: { type: "string" } }, required: ["task_id", "result"] } },
  ],
}));

