    const { message, thread_id } = args as { message: string; thread_id?: string };
    const r = await postToPartner({ type: "message", from: AGENT_NAME, message, thread_id, timestamp: new Date().toISOString() });
    if (!r.ok) return { content: [{ type: "text" as const, text: `Connection failed: ${r.error}` }] };
    return { content: [{ type: "text" as const, text: `Message sent to ${AGENT_NAME}${thread_id ? ` [thread: ${thread_id}]` : ""}` }] };
  }

  if (name === "ping_partner") {
    try {
      const response = await fetch(`http://${PARTNER_IP}:${PARTNER_PORT}`, { method: "GET", signal: AbortSignal.timeout(3000) });
      if (!response.ok) return { content: [{ type: "text" as const, text: `${AGENT_NAME} unreachable (HTTP ${response.status})` }] };
      const data = await response.json() as { agent: string; inbox: number; tasks: number };
      return { content: [{ type: "text" as const, text: `${AGENT_NAME} is ONLINE\nAgent: ${data.agent}\nUnread messages: ${data.inbox}\nPending tasks: ${data.tasks}` }] };
    } catch (e: unknown) {
      return { content: [{ type: "text" as const, text: `${AGENT_NAME} appears OFFLINE: ${e instanceof Error ? e.message : String(e)}` }] };
    }
  }

  if (name === "check_messages") {
    if (inbox.length === 0) return { content: [{ type: "text" as const, text: `No new messages from ${AGENT_NAME}.` }] };
    const messages = inbox.map((m) => `[${m.from} @ ${m.timestamp}]${m.thread_id ? ` [thread: ${m.thread_id}]` : ""}\n${m.message}`).join("\n\n---\n\n");
    const count = inbox.length; inbox.length = 0;
    return { content: [{ type: "text" as const, text: `${count} new message${count > 1 ? "s" : ""}:\n\n${messages}` }] };
  }

  if (name === "share_file") {
    const { file_path, note } = args as { file_path: string; note?: string };
    let content: string;
    try { content = fs.readFileSync(file_path, "utf-8"); } catch (e: unknown) { return { content: [{ type: "text" as const, text: `Could not read file: ${e instanceof Error ? e.message : String(e)}` }] }; }
    const filename = path.basename(file_path);
    const r = await postToPartner({ type: "shared_file", from: AGENT_NAME, filename, content, note: note || "", timestamp: new Date().toISOString() });
    if (!r.ok) return { content: [{ type: "text" as const, text: `Failed to share file: ${r.error}` }] };
    return { content: [{ type: "text" as const, text: `Shared "${filename}" (${content.length} chars) with ${AGENT_NAME}` }] };
  }

  if (name === "assign_task") {
    const { title, description } = args as { title: string; description: string };
    const task: Task = { id: makeId(), from: AGENT_NAME, title, description, status: "pending", timestamp: new Date().toISOString() };
    const r = await postToPartner({ type: "task_assigned", ...task });
    if (!r.ok) return { content: [{ type: "text" as const, text: `Failed to assign task: ${r.error}` }] };
    return { content: [{ type: "text" as const, text: `Task assigned to ${AGENT_NAME}: [${task.id}] ${title}` }] };
  }

  if (name === "check_tasks") {
    const active = assignedTasks.filter((t) => t.status !== "done");
    if (active.length === 0) return { content: [{ type: "text" as const, text: "No pending tasks assigned to you." }] };
    return { content: [{ type: "text" as const, text: `${active.length} active task(s):\n\n${active.map(t => `[${t.id}] (${t.status}) from ${t.from}\nTitle: ${t.title}\n${t.description}`).join("\n\n---\n\n")}` }] };
  }

  if (name === "complete_task") {
    const { task_id, result: resultNote } = args as { task_id: string; result: string };
    const task = assignedTasks.find((t) => t.id === task_id);
    if (!task) return { content: [{ type: "text" as const, text: `Task ${task_id} not found.` }] };
    task.status = "done";
    const r = await postToPartner({ type: "task_completed", from: AGENT_NAME, task_id, title: task.title, result: resultNote, timestamp: new Date().toISOString() });
    if (!r.ok) return { content: [{ type: "text" as const, text: `Done locally, but couldn't notify partner: ${r.error}` }] };
    return { content: [{ type: "text" as const, text: `Task [${task_id}] "${task.title}" complete. Partner notified.` }] };
  }

  return { content: [{ type: "text" as const, text: `Unknown tool: ${name}` }] };
});

const transport = new StdioServerTransport();
await mcp.connect(transport);

Bun.serve({
  port: LOCAL_PORT, hostname: "0.0.0.0",
  async fetch(req) {
    if (req.method !== "POST") {
      return new Response(JSON.stringify({ status: "running", agent: AGENT_NAME, inbox: inbox.length, tasks: assignedTasks.filter(t => t.status !== "done").length }), { status: 200, headers: { "Content-Type": "application/json" } });
    }
    try {
      const body = await req.json();
