      if (type === "message") {
        const msg: Message = { from: body.from || "Unknown", message: body.message || body.text || JSON.stringify(body), timestamp: body.timestamp || new Date().toISOString(), thread_id: body.thread_id };
        inbox.push(msg); appendToLog(msg);
        console.error(`\n>> Message from ${msg.from}${msg.thread_id ? ` [thread: ${msg.thread_id}]` : ""}: "${msg.message.slice(0, 80)}"`);
      } else if (type === "shared_file") {
        const sf: SharedFile = { from: body.from || "Unknown", filename: body.filename, content: body.content, timestamp: body.timestamp || new Date().toISOString() };
        sharedFiles.push(sf);
        const saveDir = path.join(os.homedir(), "agent-bridge-files");
        fs.mkdirSync(saveDir, { recursive: true });
        const savePath = path.join(saveDir, sf.filename);
        fs.writeFileSync(savePath, sf.content, "utf-8");
        console.error(`\n>> File from ${sf.from}: "${sf.filename}" saved to ${savePath}`);
        inbox.push({ from: sf.from, message: `File received: "${sf.filename}" → ${savePath}${body.note ? `\nNote: ${body.note}` : ""}`, timestamp: sf.timestamp });
      } else if (type === "task_assigned") {
        const task: Task = { id: body.id || makeId(), from: body.from || "Unknown", title: body.title, description: body.description, status: "pending", timestamp: body.timestamp || new Date().toISOString() };
        assignedTasks.push(task);
        console.error(`\n>> Task assigned by ${task.from}: [${task.id}] ${task.title}`);
        inbox.push({ from: task.from, message: `New task: [${task.id}] "${task.title}"\n${task.description}\nRun check_tasks to view all.`, timestamp: task.timestamp });
      } else if (type === "task_completed") {
        console.error(`\n>> Task [${body.task_id}] done by ${body.from}`);
        inbox.push({ from: body.from || "Unknown", message: `Task done: [${body.task_id}] "${body.title}"\nResult: ${body.result}`, timestamp: body.timestamp || new Date().toISOString() });
      }
      return new Response(JSON.stringify({ status: "delivered" }), { status: 200, headers: { "Content-Type": "application/json" } });
    } catch { return new Response("Bad request", { status: 400 }); }
  },
});

console.error(`Agent Bridge v3 on 0.0.0.0:${LOCAL_PORT} | Partner: ${AGENT_NAME} @ ${PARTNER_IP}:${PARTNER_PORT}`);
