  sweepExpiredRooms,
  getRoomCount,
} from "./rooms.js";

const app = new Hono();
const startTime = Date.now();

// ── Rate limiting ─────────────────────────────────────────────────────────────
// Simple in-memory rate limiter: max N calls per window per key
const rateLimitStore = new Map<string, { count: number; windowStart: number }>();

function checkRateLimit(key: string, max: number, windowMs: number): boolean {
  const now = Date.now();
  const state = rateLimitStore.get(key);
  if (!state || now - state.windowStart > windowMs) {
    rateLimitStore.set(key, { count: 1, windowStart: now });
    return true;
  }
  if (state.count >= max) return false;
  state.count++;
  return true;
}

// ── GC sweep every hour ───────────────────────────────────────────────────────
setInterval(() => {
  const swept = sweepExpiredRooms();
  if (swept > 0) console.log(`[gc] swept ${swept} expired rooms`);
  // Also clean up stale rate limit entries
  const now = Date.now();
  for (const [key, state] of rateLimitStore) {
    if (now - state.windowStart > 60 * 60 * 1000) rateLimitStore.delete(key);
  }
}, 60 * 60 * 1000);

// ── REST endpoints ────────────────────────────────────────────────────────────

app.get("/health", (c) => {
  return c.json({
    status: "ok",
    uptime_seconds: Math.floor((Date.now() - startTime) / 1000),
    room_count: getRoomCount(),
  });
});

app.get("/rooms/new", (c) => {
  // Rate limit room creation: 100 rooms/hr per IP
  const ip = c.req.header("x-forwarded-for") ?? "unknown";
  if (!checkRateLimit(`room_create:${ip}`, 100, 60 * 60 * 1000)) {
    return c.json({ error: "rate_limit_exceeded" }, 429);
  }

  const code = createRoom();
  const baseUrl = new URL(c.req.url).origin;
  return c.json({
    room: code,
    claude_code_url: `${baseUrl}/mcp?room=${code}&name=YOUR_NAME`,
    antigravity_url: `${baseUrl}/mcp?room=${code}&name=YOUR_NAME`,
    instructions:
      "Replace YOUR_NAME with your name. Add the URL to your AI tool's MCP config.",
  });
});

