async function callTool(toolName: string, args: Record<string, string> = {}) {
  const url = `${SERVER_URL}/mcp?room=${ROOM}&name=${NAME}`;
  const body = {
    jsonrpc: "2.0",
    id: 1,
    method: "tools/call",
    params: { name: toolName, arguments: args },
